// Total objects: 478

export const MAXOCLASSES = 18; // C ref: objclass.h enum objclass_classes

// Computed at init: first object index for each class, probability totals
export const bases = new Array(MAXOCLASSES + 2).fill(0);
export const oclass_prob_totals = new Array(MAXOCLASSES).fill(0);

// Bidirectional alias helper: creates getter/setter so writes propagate between names.
// objectData is mutable (shuffled at init), so static-value aliases would diverge.
function setAliasPair(obj, canonical, alias) {
    if (!(canonical in obj) && !(alias in obj)) return;
    const val = obj[canonical] ?? obj[alias];
    delete obj[canonical]; delete obj[alias];
    let _v = val;
    Object.defineProperty(obj, canonical, { get() { return _v; }, set(v) { _v = v; }, enumerable: true, configurable: true });
    Object.defineProperty(obj, alias, { get() { return _v; }, set(v) { _v = v; }, enumerable: false, configurable: true });
}

// Normalize objectData entries: add backward-compat aliases for legacy JS field names
// C ref: struct objclass in include/objclass.h
function normalizeObjectFields(obj) {
  // Primary → alias (C-canonical → legacy JS)
  setAliasPair(obj, "oc_name", "name");
  setAliasPair(obj, "oc_descr", "desc");
  setAliasPair(obj, "oc_color", "color");
  setAliasPair(obj, "oc_prob", "prob");
  setAliasPair(obj, "oc_delay", "delay");
  setAliasPair(obj, "oc_wt", "weight");
  setAliasPair(obj, "oc_cost", "cost");
  setAliasPair(obj, "oc_wsdam", "sdam");
  setAliasPair(obj, "oc_wldam", "ldam");
  setAliasPair(obj, "oc_oc1", "oc1");
  setAliasPair(obj, "oc_oc2", "oc2");
  setAliasPair(obj, "oc_nutrition", "nutrition");
  setAliasPair(obj, "oc_material", "material");
  setAliasPair(obj, "oc_oprop", "prop");
  setAliasPair(obj, "oc_dir", "dir");
  setAliasPair(obj, "oc_subtyp", "sub");
  // C macro alias: oc_skill == oc_subtyp (objclass.h)
  setAliasPair(obj, "oc_subtyp", "oc_skill");
  // C bit flag aliases
  setAliasPair(obj, "merge", "oc_merge");
  setAliasPair(obj, "magic", "oc_magic");
  setAliasPair(obj, "charged", "oc_charged");
  setAliasPair(obj, "big", "oc_big");
  // C macro aliases: oc_bimanual == oc_bulky == oc_big (objclass.h)
  setAliasPair(obj, "big", "oc_bimanual");
  setAliasPair(obj, "big", "oc_bulky");
}

// Apply aliases to all objectData entries at module load time
for (let i = 0; i < objectData.length; i++) normalizeObjectFields(objectData[i]);

// C ref: o_init.c init_objects() — compute bases[] and oclass_prob_totals[]
export function initObjectData() {
    // C ref: o_init.c — bases[0..MAXOCLASSES] = 0, first = MAXOCLASSES (= FIRST_OBJECT)
    for (let i = 0; i <= MAXOCLASSES; i++) bases[i] = 0;
    let first = MAXOCLASSES; // skip generic objects (indices 0..MAXOCLASSES-1)
    let prevOclass = -1;
    while (first < objectData.length) {
        const oclass = objectData[first].oc_class;
        let last = first + 1;
        while (last < objectData.length && objectData[last].oc_class === oclass)
            last++;
        // C only sets bases on ascending class transitions
        if (oclass > prevOclass) {
            bases[oclass] = first;
            prevOclass = oclass;
        }
        first = last;
    }
    // C: bases[MAXOCLASSES] = NUM_OBJECTS
    bases[MAXOCLASSES] = objectData.length;
    bases[MAXOCLASSES + 1] = objectData.length;
    // Fill gaps: if a class has no objects, point to next class
    for (let i = MAXOCLASSES - 1; i >= 0; i--) {
        if (!bases[i]) bases[i] = bases[i + 1];
    }
    // Compute probability totals per class
    for (let oc = 0; oc < MAXOCLASSES; oc++) {
        let sum = 0;
        for (let i = bases[oc]; i < bases[oc + 1]; i++) {
            sum += objectData[i].prob || 0;
        }
        oclass_prob_totals[oc] = sum;
    }
}

